import React, { useRef, useEffect } from 'react';

function GifAnimationControlledByScroll({ scrollPercentage, frames }) {
  const canvasRef = useRef(null);
  const currentFrame = Math.floor(scrollPercentage * frames.length);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const frame = frames[currentFrame];

    if (frame) {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(frame, 0, 0, canvas.width, canvas.height);
    }
  }, [scrollPercentage, frames, currentFrame]);

  return (
    <div className="GifAnimationControlledByScroll">
      <canvas ref={canvasRef} width={frame.width} height={frame.height} />
    </div>
  );
}

export default GifAnimationControlledByScroll;
